<div class="d-flex justify-content-between align-items-center mb-4">
    <div><h2 class="h4 mb-1">Pedidos</h2><p class="text-muted mb-0">Filtre por status e acompanhe toda a fila operacional.</p></div>
    <form class="d-flex gap-2"><select name="status" class="form-select"><option value="">Todos</option><?php foreach (\App\Models\Order::STATUSES as $item): ?><option value="<?= e($item) ?>" <?= $status === $item ? 'selected' : '' ?>><?= e($item) ?></option><?php endforeach; ?></select><button class="btn btn-outline-dark">Filtrar</button></form>
